    body=hero(prefix,'Security services','Assess exposure. <span class="text-gradient">Strengthen decisions.</span>','PDDG provides risk-driven cybersecurity assessments, clear reporting, and practical remediation guidance across digital, human, physical, and wireless control layers.',[button('Book a Security Fit Call',href(prefix,'book-a-security-fit-call')),button('View Our Approach',href(prefix,'approach'),True)],crumbs=[('Home',''),('Services',None)])
    body+=f'''<section class="section section-border"><div class="container">{section_head('Full capability set','Choose the assessment path that matches the decision.','The exact methodology, assets, test actions, safeguards, and deliverables are confirmed during scoping.')}<div class="grid-3">{''.join(service_card(prefix,s,i) for i,s in enumerate(SERVICES,1))}</div></div></section>'''
