    body+=f'''<section class="section section-border"><div class="narrow">{section_head('Service questions',f'Common questions about {escape(s["title"]).lower()}.','')}{faq_html(s['faqs'])}</div></section>'''+cta(prefix)
    page(route,s['title']+' Services',s['summary'],body,'services')

