def approach_page():
    prefix='../'
    body=hero(prefix,'Our approach','From technical evidence to <span class="text-gradient">clear business action.</span>','PDDG uses a structured, risk-driven approach to define scope, evaluate exposure, connect findings to business context, support remediation, and validate improvement.',[button('Book a Security Fit Call',href(prefix,'book-a-security-fit-call')),button('Explore Services',href(prefix,'services'),True)],crumbs=[('Home',''),('Approach',None)])
    body+=f'''<section class="section section-border"><div class="container">{section_head('Engagement process','A five-stage path from uncertainty to accountable action.','Each stage connects technical evidence to a clear decision, responsible owner, and measurable next action.')}{process_html()}</div></section>'''
    matrix=''.join(f'<div class="matrix-cell">{text}</div>' for text in ['Monitor','Plan','Prioritize','Plan','Prioritize','Accelerate','Prioritize','Accelerate','Immediate decision'])
    body+=f'''<section class="section section-dark"><div class="container">{section_head('Risk prioritization','Technical severity is not the final decision.','PDDG considers likelihood and exploitability alongside business impact, exposure, compensating controls, urgency, dependencies, and remediation effort.')}<div class="matrix reveal"><div class="matrix-y">Business impact</div><div class="matrix-main"><div class="matrix-grid">{matrix}</div><div class="matrix-x">Likelihood & exploitability</div><div class="matrix-labels"><span>Low</span><span>Moderate</span><span>High</span></div></div></div><div class="tag-list"><span class="tag">Asset importance</span><span class="tag">Data sensitivity</span><span class="tag">Operational impact</span><span class="tag">Exposure</span><span class="tag">Compensating controls</span><span class="tag">Remediation effort</span></div></div></section>'''
    body+=f'''<section class="section section-border"><div class="container">{section_head('Reporting audiences','One evidence base. Two decision views.','Technical and executive audiences need different framing without losing traceability to the underlying evidence.')}<div class="split-panel"><div class="split-side reveal"><span class="mono">Technical teams</span><h3>Reproduce, remediate, and validate.</h3>{list_html(['Affected assets and conditions','Reproducible technical evidence','Practical remediation guidance','Validation and retest status'],'split-list')}</div><div class="split-side reveal"><span class="mono">Executive teams</span><h3>Understand material exposure and ownership.</h3>{list_html(['Business and operational impact','Priority and urgency context','Accountable ownership','Remaining risk and next decision'],'split-list')}</div></div></div></section>'''
    body+=f'''<section class="section section-dark"><div class="container">{section_head('Evidence handling','Collect only what is necessary to support the finding.','Evidence practices are established during scoping and may include minimization, redaction, approved storage, secure transfer, access controls, retention periods, and destruction expectations.')}<div class="grid-3"><article class="card card-pad reveal"><span class="eyebrow">Minimize</span><h3>Limit sensitive information.</h3><p>Collect proportionate evidence and avoid unnecessary personal, regulated, or operational data.</p></article><article class="card card-pad reveal"><span class="eyebrow">Protect</span><h3>Control storage and transfer.</h3><p>Use agreed channels, access restrictions, handling expectations, and retention periods.</p></article><article class="card card-pad reveal"><span class="eyebrow">Explain</span><h3>State limitations clearly.</h3><p>Document assumptions, exclusions, constraints, and what the assessment does not establish.</p></article></div></div></section>'''+cta(prefix)
    page('approach','Our Risk-Driven Approach','A structured, authorized approach connecting technical evidence to business impact and practical remediation.',body,'approach')

