def form_page(route, title, eyebrow, headline, summary, form_subject, fields, active='contact', note='Do not include credentials, vulnerability details, protected information, or sensitive operational data in this form.'):
    prefix=depth_prefix(route)
    form_fields=''
    for field in fields:
        kind,name,label,full,options=field
        cls='field full' if full else 'field'
        if kind=='textarea': control=f'<textarea id="{name}" name="{label}" required></textarea>'
        elif kind=='select': control=f'<select id="{name}" name="{label}" required><option value="">Select an option</option>'+''.join(f'<option>{escape(o)}</option>' for o in options)+'</select>'
        else: control=f'<input id="{name}" name="{label}" type="{kind}" required>'
        form_fields+=f'<div class="{cls}"><label for="{name}">{escape(label)}</label>{control}</div>'
    form=f'''<form class="form-card reveal" data-mail-form data-subject="{escape(form_subject)}"><div class="form-grid">{form_fields}</div><p class="form-note">{escape(note)}</p><button class="btn" type="submit">Prepare email {ARROW}</button><div class="form-status" role="status"></div></form>'''
    body=hero(prefix,eyebrow,headline,summary,[button('Call '+COMPANY['phone'],'tel:+13015321463',True)],crumbs=[('Home',''),(title,None)])
    body+=f'''<section class="section section-border"><div class="container contact-grid"><aside class="contact-info reveal"><div class="contact-chip"><small>Phone</small><a href="tel:+13015321463">{COMPANY['phone']}</a></div><div class="contact-chip"><small>Email</small><a href="mailto:{COMPANY['email']}">{COMPANY['email']}</a></div><div class="contact-chip"><small>Office</small><strong>{COMPANY['address']}</strong></div><div class="contact-chip"><small>Hours</small><strong>{COMPANY['hours']}</strong></div><div class="article-note" style="margin-top:4px">For an urgent or active security incident, call rather than relying on a website form. Incident-response availability must be confirmed separately.</div></aside>{form}</div></section>'''+cta(prefix,'Need a different starting point?','Review the service and industry pages, or call PDDG to discuss the most appropriate next step.')
    page(route,title,summary,body,active)

