def write_assets_and_config():
    favicon='''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64"><rect width="64" height="64" rx="15" fill="#06111d"/><path d="M32 8 52 17v14c0 13-7.5 21-20 27C19.5 52 12 44 12 31V17L32 8Z" fill="none" stroke="#2ce6d1" stroke-width="4"/><path d="M22 34 29 41 43 24" fill="none" stroke="#f2f8fb" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"/></svg>'''
    (ROOT/'assets/images/favicon.svg').write_text(favicon,encoding='utf-8')
    (ROOT/'.nojekyll').write_text('',encoding='utf-8')
    manifest='''{"name":"Pinnacle Digital Defense Group","short_name":"PDDG","start_url":"./","display":"standalone","background_color":"#02070d","theme_color":"#02070d","icons":[{"src":"assets/images/favicon.svg","sizes":"any","type":"image/svg+xml"}]}'''
    (ROOT/'site.webmanifest').write_text(manifest,encoding='utf-8')
    (ROOT/'robots.txt').write_text(f'User-agent: *\nAllow: /\nSitemap: {BASE}/sitemap.xml\n',encoding='utf-8')
    routes=['']+['services']+[f'services/{s["slug"]}' for s in SERVICES]+['industries']+[f'industries/{x["slug"]}' for x in INDUSTRIES]+['approach','resources']+[f'resources/{r["slug"]}' for r in RESOURCES]+['about','contact','book-a-security-fit-call','request-a-sample-report','case-studies','frequently-asked-questions','privacy-policy','terms-and-conditions','accessibility-statement']
    urls=''.join(f'<url><loc>{BASE}{"/"+r+"/" if r else "/"}</loc></url>' for r in routes)
    (ROOT/'sitemap.xml').write_text('<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">'+urls+'</urlset>',encoding='utf-8')
    workflow='''name: Deploy static site to GitHub Pages\n\non:\n  push:\n    branches: [\"main\"]\n  workflow_dispatch:\n\npermissions:\n  contents: read\n  pages: write\n  id-token: write\n\nconcurrency:\n  group: pages\n  cancel-in-progress: true\n\njobs:\n  deploy:\n    environment:\n      name: github-pages\n      url: ${{ steps.deployment.outputs.page_url }}\n    runs-on: ubuntu-latest\n    steps:\n      - name: Checkout\n        uses: actions/checkout@v4\n      - name: Configure Pages\n        uses: actions/configure-pages@v5\n      - name: Upload artifact\n        uses: actions/upload-pages-artifact@v3\n        with:\n          path: .\n      - name: Deploy to GitHub Pages\n        id: deployment\n        uses: actions/deploy-pages@v4\n'''
    (ROOT/'.github/workflows').mkdir(parents=True,exist_ok=True)
    (ROOT/'.github/workflows/deploy.yml').write_text(workflow,encoding='utf-8')
    readme='''# PDDG Premium Cybersecurity Website Redesign\n\nA complete static redesign of the Pinnacle Digital Defense Group website for GitHub Pages. The project preserves the existing service names, industry pages, core business content, legal pages, resources, contact details, and public URL structure while replacing the design and front-end experience.\n\n## Deploy to GitHub Pages\n\n1. Extract the ZIP.\n2. Replace the contents of your existing `pddg-cybersecurity` repository with the extracted files.\n3. Commit and push everything to the `main` branch.\n4. In GitHub, open **Settings → Pages**.\n5. Under **Build and deployment**, choose **GitHub Actions**.\n6. Open the **Actions** tab and confirm that “Deploy static site to GitHub Pages” completes successfully.\n\nThe site is built with plain HTML, CSS, and JavaScript, so there is no npm installation or build command.\n\n## Forms\n\nThe site is static. Contact, booking, and sample-report forms prepare an email in the visitor's email application and do not store form data on the website. For production lead capture, connect the forms to your CRM or form endpoint.\n\n## Main files\n\n- `index.html` — homepage\n- `services/`, `industries/`, `resources/` — all preserved routes\n- `assets/css/styles.css` — complete responsive design system\n- `assets/js/main.js` — animations, navigation, accordions, service tabs, checklist, and form behavior\n- `.github/workflows/deploy.yml` — automatic GitHub Pages deployment\n\n## Editing content\n\nThe generated HTML files are deployment-ready. `generate_site.py` is also included as the structured source used to generate the pages. Edit its content dictionaries and run `python generate_site.py` to regenerate the site consistently.\n'''
    (ROOT/'README.md').write_text(readme,encoding='utf-8')

def not_found():
    prefix=''
    body=hero(prefix,'404 · Page not found','The requested signal is <span class="text-gradient">outside the mapped scope.</span>','The page may have moved, or the address may be incorrect.',[button('Return home',href(prefix,'')),button('View services',href(prefix,'services'),True)],inner=False,visual='orbit')
    html=page('', 'Page Not Found', 'The requested page could not be found.', body, 'home')
    # page() wrote index, so write separately using a compact duplicate built from existing index shell.
    source=(ROOT/'index.html').read_text(encoding='utf-8')
    start=source.find('<main id="main">')+len('<main id="main">')
    end=source.find('</main>',start)
    custom=source[:start]+body+source[end:]
    (ROOT/'404.html').write_text(custom.replace('<title>Risk-Driven Cybersecurity Assessments | PDDG</title>','<title>Page Not Found | PDDG</title>',1),encoding='utf-8')


def main():
    write_assets_and_config()
    home_page()
    services_hub()
    for s in SERVICES: service_page(s)
    industries_hub()
    for x in INDUSTRIES: industry_page(x)
    approach_page()
    resources_hub()
    for r in RESOURCES: resource_page(r)
    about_page()
    general_pages()
    faq_page()
    case_studies_page()
    legal_pages()
    # build 404 from current index without overwriting root page
    source=(ROOT/'index.html').read_text(encoding='utf-8')
    prefix=''
    b=hero(prefix,'404 · Page not found','The requested signal is <span class="text-gradient">outside the mapped scope.</span>','The page may have moved, or the address may be incorrect.',[button('Return home',href(prefix,'')),button('View services',href(prefix,'services'),True)],inner=False,visual='orbit')
    st=source.find('<main id="main">')+len('<main id="main">'); en=source.find('</main>',st)
    (ROOT/'404.html').write_text(source[:st]+b+source[en:],encoding='utf-8')
    print('Generated site:', ROOT)

if __name__=='__main__':
    main()
